import random

def monte_carlo_root(f, a, b, n, precision=0):
    def is_root(x):
        return abs(f(x)) < 10**(-precision)

    count = 0
    for _ in range(n):
        x = random.uniform(a, b)
        if is_root(x):
            count += 1

    # Estimate the root based on the proportion of samples that are roots
    root_estimate = (a + b) / 2
    if count > n // 2:
        root_estimate = b
    elif count < n // 2:
        root_estimate = a

    return round(root_estimate, precision)

# Example usage:
